(1, '华为Mate 60 Pro智能手机', '手机', 6999.00, '华为旗舰手机，搭载麒麟9000S处理器，支持卫星通话，拥有出色的拍照能力和超长续航。', '{"brand": "华为", "color": ["雅丹黑", "白沙银", "南糯紫"], "model": "Mate 60 Pro", "camera": "5000万像素主摄", "screen": "6.82英寸OLED", "battery": "5000mAh", "network": "5G", "storage": ["256GB", "512GB", "1TB"]}', 150, '2026-03-04 18:37:17'),
(2, '小米14 Ultra手机', '手机', 5999.00, '小米高端旗舰，徕卡影像系统，骁龙8 Gen3处理器，专业级拍照体验。', '{"brand": "小米", "color": ["黑色", "白色"], "model": "14 Ultra", "camera": "徕卡专业影像系统", "screen": "6.73英寸AMOLED", "battery": "5000mAh", "network": "5G", "storage": ["256GB", "512GB"]}', 200, '2026-03-04 18:37:17'),
(3, 'MacBook Pro 14英寸笔记本电脑', '电脑', 14999.00, '苹果MacBook Pro 14英寸，M3 Pro芯片，18GB统一内存，512GB固态硬盘，专业级生产力工具。', '{"cpu": "M3 Pro", "brand": "Apple", "model": "MacBook Pro 14", "memory": "18GB", "screen": "14.2英寸Liquid Retina XDR", "weight": "1.55kg", "battery": "最长17小时续航", "storage": "512GB SSD"}', 80, '2026-03-04 18:37:17'),
