INSERT INTO `knowledge_docs` (`id`, `title`, `content`, `category`, `source`, `created_at`) VALUES
(1, 'iPhone 15 Pro Max产品介绍', 'iPhone 15 Pro Max采用钛金属机身设计，配备6.7英寸超视网膜XDR显示屏，搭载A17 Pro芯片，支持USB-C接口。相机系统包括4800万像素主摄、1200万像素超广角和1200万像素长焦镜头，支持4K60fps视频录制。电池容量4422mAh，支持27W有线充电和15W无线充电。起售价9999元，提供256GB、512GB、1TB存储选项。', 'product', '官方资料', '2026-04-18 01:40:46'),
(2, '华为Mate 60 Pro产品介绍', '华为Mate 60 Pro采用昆仑玻璃屏幕，配备6.8英寸OLED曲面屏，搭载麒麟9000S处理器，支持5G网络。相机系统包括5000万像素主摄、1300万像素超广角和4800万像素长焦镜头，支持可变光圈。电池容量5000mAh，支持66W有线充电和50W无线充电。起售价6999元，提供256GB、512GB、1TB存储选项。', 'product', '官方资料', '2026-04-18 01:40:46'),
(3, '小米14 Pro产品介绍', '小米14 Pro采用陶瓷机身设计，配备6.73英寸2K AMOLED屏幕，搭载骁龙8 Gen 3处理器，支持120W有线充电。相机系统包括5000万像素徕卡主摄、5000万像素超广角和5000万像素长焦镜头，支持8K视频录制。电池容量5500mAh，支持50W无线充电。起售价4999元，提供256GB、512GB、1TB存储选项。', 'product', '官方资料', '2026-04-18 01:40:46'),
(4, '三星Galaxy S24 Ultra产品介绍', '三星Galaxy S24 Ultra采用 Dynamic AMOLED 2X屏幕，配备6.8英寸2K+显示屏，搭载骁龙8 Gen 3处理器，支持S Pen。相机系统包括2亿像素主摄、5000万像素超广角、5000万像素长焦和1000万像素潜望式长焦镜头，支持100倍数码变焦。电池容量5000mAh，支持45W有线充电和15W无线充电。起售价8999元，提供256GB、512GB、1TB存储选项。', 'product', '官方资料', '2026-04-18 01:40:46'),
(5, 'OPPO Find X7 Ultra产品介绍', 'OPPO Find X7 Ultra采用双曲屏设计，配备6.82英寸2K AMOLED屏幕，搭载骁龙8 Gen 3处理器，支持100W有线充电。相机系统包括5000万像素哈苏主摄、5000万像素超广角和5000万像素潜望式长焦镜头，支持10倍光学变焦。电池容量5500mAh，支持50W无线充电。起售价5999元，提供256GB、512GB存储选项。', 'product', '官方资料', '2026-04-18 01:40:46'),
(6, 'vivo X100 Pro产品介绍', 'vivo X100 Pro采用曲面屏设计，配备6.78英寸2K AMOLED屏幕，搭载天玑9300处理器，支持80W有线充电。相机系统包括5000万像素蔡司主摄、5000万像素超广角和6400万像素潜望式长焦镜头，支持8倍光学变焦。电池容量5400mAh，支持50W无线充电。起售价4999元，提供256GB、512GB存储选项。', 'product', '官方资料', '2026-04-18 01:40:46'),
(7, '荣耀Magic6 Pro产品介绍', '荣耀Magic6 Pro采用全面屏设计，配备6.8英寸OLED屏幕，搭载骁龙8 Gen 3处理器，支持66W有线充电。相机系统包括5000万像素主摄、5000万像素超广角和5000万像素长焦镜头，支持OIS光学防抖。电池容量5600mAh，支持50W无线充电。起售价5699元，提供256GB、512GB存储选项。', 'product', '官方资料', '2026-04-18 01:40:46'),
(8, '一加12产品介绍', '一加12采用陶瓷机身设计，配备6.82英寸2K AMOLED屏幕，搭载骁龙8 Gen 3处理器，支持100W有线充电。相机系统包括5000万像素哈苏主摄、5000万像素超广角和6400万像素长焦镜头，支持3倍光学变焦。电池容量5400mAh，支持50W无线充电。起售价4999元，提供256GB、512GB存储选项。', 'product', '官方资料', '2026-04-18 01:40:46'),
(9, 'MacBook Pro 16英寸产品介绍', 'MacBook Pro 16英寸搭载M3 Pro或M3 Max芯片，配备16英寸Liquid Retina XDR显示屏，分辨率3456×2234。内存可选18GB-128GB，存储可选512GB-8TB。支持MagSafe充电，配备三个Thunderbolt 4接口和一个HDMI接口。电池续航最长可达22小时，起售价19999元。', 'product', '官方资料', '2026-04-18 01:40:46'),
(10, 'ThinkPad X1 Carbon 2024产品介绍', 'ThinkPad X1 Carbon 2024采用碳纤维机身，重量仅1.12kg，配备14英寸2.8K OLED屏幕，搭载第14代英特尔酷睿处理器。内存可选16GB-64GB，存储可选512GB-2TB。键盘采用背光设计，支持指纹识别和人脸识别。电池续航最长可达15小时，起售价9999元。', 'product', '官方资料', '2026-04-18 01:40:46'),
(32, '配送时效说明', '北京、上海、广州、深圳等一线城市，订单下单后1-2天内送达；二线城市2-3天内送达；三线及以下城市3-5天内送达。偏远地区（如新疆、西藏、青海等）5-7天内送达。部分特殊商品（如大家电、定制商品）可能需要额外1-2天配送时间。', 'logistics', '物流政策', '2026-04-18 01:40:46'),
(33, '运费规则说明', '全场满99元包邮，不满99元收取10元运费。部分特殊商品（如大家电、重物）可能需要额外收取运费，具体以商品详情页为准。偏远地区（如新疆、西藏、青海等）满199元包邮，不满199元收取20元运费。', 'logistics', '物流政策', '2026-04-18 01:40:46'),
(34, '物流追踪方式', '订单发货后，系统会自动发送物流单号至您的手机和邮箱。您可以在订单详情页查看实时物流信息，也可以通过快递公司官网或APP查询。支持的快递公司包括顺丰、京东物流、中通、韵达、申通等。', 'logistics', '物流政策', '2026-04-18 01:40:46'),
(35, '配送服务说明', '大家电商品（如冰箱、洗衣机、空调等）支持上门安装服务，部分商品需要收取安装费用，具体以商品详情页为准。部分商品支持预约配送，您可以在下单时选择具体的配送时间。', 'logistics', '物流政策', '2026-04-18 01:40:46'),
(36, '物流异常处理', '如遇物流延迟或异常，您可以联系客服申请催件或查询具体情况。如商品在运输过程中损坏，您可以拒收并联系客服申请退款或重新发货。如物流信息长时间未更新，您可以联系客服进行处理。', 'logistics', '物流政策', '2026-04-18 01:40:46'),
(37, '大件商品配送', '冰箱、洗衣机、空调等大家电商品由专业配送团队送货上门，配送前会提前1天电话联系确认收货时间。大家电支持免费送货入户，但不包含安装服务（安装需另收费或联系品牌官方售后）。', 'logistics', '物流政策', '2026-04-18 01:40:46'),
(38, '同城急送服务', '部分城市支持同城急送服务，下单后2-4小时送达，加收15-25元服务费。适用于紧急需要的商品，如手机配件、日用品等小件商品。具体覆盖城市以结算页显示为准。', 'logistics', '物流政策', '2026-04-18 01:40:46'),
(39, '退换货政策', '支持7天无理由退换货，商品需保持全新未使用状态，包装完好。质量问题支持15天内退换货，需要提供相关质量问题证明。部分特殊商品（如贴身衣物、美妆产品、定制商品）不支持无理由退换货，具体以商品详情页为准。', 'policy', '售后政策', '2026-04-18 01:40:46'),
(40, '保修政策总则', '手机、电脑等数码产品保修1年；大家电产品保修3年；小家电产品保修1年；服装鞋帽类产品不保修。保修范围仅包括产品本身质量问题，不包括人为损坏、自行拆卸等情况。保修期从签收之日开始计算。', 'policy', '售后政策', '2026-04-18 01:40:46'),
(41, '数码产品保修细则', '手机、平板、笔记本等数码产品享受1年官方保修服务。保修范围包括：硬件故障、性能异常、屏幕坏点（超过3个）等。不保修情况：进液、摔落挤压、私自拆修、人为损坏、超出保修期。保修时需提供购买凭证（订单号或发票）。', 'policy', '售后政策', '2026-04-18 01:40:46'),
(42, '大家电保修细则', '冰箱、洗衣机、空调等大家电产品享受3年整机保修，压缩机等核心部件保修6-10年（视品牌而定）。保修范围包括：制冷/制热效果异常、噪音过大、漏水漏电等质量问题。安装调试费用需用户自行承担。', 'policy', '售后政策', '2026-04-18 01:40:46'),
(43, '支付方式说明', '支持支付宝、微信支付、银联云闪付、信用卡支付、花呗分期、京东白条等多种支付方式。部分商品支持分期付款，具体以商品详情页为准。大额订单（超过5000元）可能需要额外验证身份信息。', 'policy', '支付政策', '2026-04-18 01:40:46'),
(44, '分期付款说明', '花呗分期支持3期、6期、12期免息（部分商品）；信用卡分期支持3期、6期、12期、24期，具体费率以银行页面显示为准；京东白条支持3期、6期、12期、24期免息（部分商品）。分期金额上限因商品和信用额度而异。', 'policy', '支付政策', '2026-04-18 01:40:46'),
(52, '客服联系方式', '平台提供多种客服渠道：①客服热线400-123-4567（工作日9:00-22:00，周末10:00-18:00）；②APP/官网在线客服（7×24小时智能+人工）；③官方微信公众号"ExampleService"；④邮箱support@example.com（1-2个工作日内回复）。', 'service', '客服政策', '2026-04-18 01:40:46'),
(53, '售后维修流程', '商品出现质量问题需维修时，请按以下流程操作：①登录APP→我的订单→申请售后；②选择问题类型并上传照片/视频凭证；③客服审核（1-2个工作日）；④审核通过后寄回或等待上门取件；⑤维修完成后寄回（一般3-7个工作日）。', 'service', '客服政策', '2026-04-18 01:40:46'),
(54, '投诉与建议通道', '如您对服务不满意，可通过以下渠道反馈：①在线客服直接转接投诉专员；②拨打客服热线按9号键进入投诉通道；③发送邮件至complaints@example.com（注明订单号和问题描述）。我们承诺24小时内响应，7个工作日内给出处理结果。', 'service', '客服政策', '2026-04-18 01:40:46'),
(55, '常见问题FAQ-订单相关', 'Q: 如何修改收货地址？A: 未发货前可在订单详情页自行修改；已发货需联系客服尝试拦截（成功率非100%）。Q: 如何取消订单？A: 未发货前可自助取消；已发货需拒收后申请退款。Q: 订单多久发货？A: 一般24小时内发出（工作日），大件商品可能需要1-3天备货期。', 'service', '客服政策', '2026-04-18 01:40:46'),
(56, '常见问题FAQ-支付相关', 'Q: 支付失败怎么办？A: 请检查银行卡余额、网络状态，或尝试更换支付方式。如持续失败请联系客服。Q: 如何申请退款？A: 订单详情页→申请退款→选择原因→提交审核（1-3个工作日到账）。Q: 发票信息填错了？A: 未开出前可修改；已开出需联系客服作废重开。', 'service', '客服政策', '2026-04-18 01:40:46'),
(57, 'iPhone 15系列详细规格', 'iPhone 15 Pro Max详细参数：屏幕6.7英寸OLED 2622×1206分辨率，A17 Pro芯片（6核CPU+6核GPU），内存8GB，存储256GB/512GB/1TB，后置三摄（48MP主摄f/1.78+12MP超广角f/2.2+12MP长焦f/2.8），前置12MP，电池4422mAh，27W有线+15W无线+7.5W MagSafe，IP68防水防尘，钛金属边框，USB-C接口，重量221g。', 'product', '技术参数', '2026-04-18 01:40:46'),
(58, '华为Mate 60系列详细规格', '华为Mate 60 Pro详细参数：屏幕6.82英寸OLED 2720×1260分辨率，麒麟9000S处理器，内存12GB/16GB，存储256GB/512GB/1TB，后置三摄（50MP主摄f/1.4-f/4.0可变光圈+13MP超广角f/2.2+48MP长焦f/3.0 OIS），前置13MP+3D深感，电池5000mAh，66W有线+50W无线+15W反向无线，IP68防水防尘，昆仑玻璃二代，卫星通话功能，重量225g。', 'product', '技术参数', '2026-04-18 01:40:46'),
(59, '小米14系列详细规格', '小米14 Pro详细参数：屏幕6.73英寸AMOLED 3200×1440分辨率120Hz LTPO，骁龙8 Gen 3处理器，内存12GB/16GB，存储256GB/512GB/1TB，后置三摄（50MP徕卡主摄f/1.42-f/4.0光圈+50MP超广角f/2.2+50MP长焦f/2.0 OIS），前置32MP，电池5400mAh，120W有线+50W无线+10W反向无线，IP68防水防尘，陶瓷/玻璃机身，重量223g。', 'product', '技术参数', '2026-04-18 01:40:46'),
(60, 'MacBook Pro M3系列配置对比', 'MacBook Pro 14英寸M3版：8核CPU+10核GPU+16GB内存+512GB存储，起价14999元；M3 Pro版：11/12核CPU+14/18核GPU+18GB内存+512GB存储，起价16999元；M3 Max版：14/16核CPU+30/40核GPU+36GB内存+1TB存储，起价19999元；16英寸版本同配置贵3000-4000元。全系支持ProMotion 120Hz自适应刷新率。', 'product', '技术参数', '2026-04-18 01:40:46'),
(61, '2024年手机选购指南-旗舰机对比', '2024年旗舰手机推荐：①影像首选：vivo X100 Pro（蔡司认证+潜望长焦）；②性能首选：一加12（骁龙8 Gen 3+100W快充）；③商务首选：华为Mate 60 Pro（卫星通话+鸿蒙生态）；④性价比：小米14 Pro（徕卡影像+价格优势）；⑤苹果生态：iPhone 15 Pro Max（A17 Pro+iOS）。根据预算和需求选择即可。', 'product', '选购指南', '2026-04-18 01:40:46'),
(62, '笔记本电脑选购建议', '选择笔记本需考虑以下因素：①用途（办公/游戏/创作）→决定CPU/GPU配置；②便携性需求→重量1.2kg以内为轻薄本，2kg以上为性能本；③屏幕素质→设计师优先考虑色域覆盖，办公用户关注护眼；④续航→经常外出选长续航机型；⑤预算→5000-8000元主流价位，10000元以上高端定位。', 'product', '选购指南', '2026-04-18 01:40:46'),
(63, '家电购买注意事项', '购买大家电时请注意：①测量安装位置尺寸（预留散热空间）；②确认电源插座规格（空调需16A专用插座）；③了解售后政策（上门安装是否收费）；④查看能效等级（一级最省电）；⑤关注噪音参数（冰箱≤40dB、空调≤25dB为宜）；⑥大件商品配送时间可能较长（3-7天）。', 'product', '选购指南', '2026-04-18 01:40:46'),
(64, '护肤品成分入门指南', '常见有效成分及功效：①保湿类：透明质酸钠、甘油、神经酰胺；②抗老类：视黄醇（A醇）、胜肽、玻色因；③美白类：烟酰胺、VC衍生物、377；④修护类：二裂酵母发酵产物溶胞物、积雪草提取物；⑤控油类：水杨酸、果酸、锌。建议根据肤质和诉求搭配使用，初次尝试从低浓度开始。', 'product', '选购指南', '2026-04-18 01:40:46'),
(65, '运动鞋选购要点', '选择运动鞋需注意：①跑步鞋→注重缓震回弹（Boost/Light Foam等中底材料）、重量（250g以内为轻量级）；②篮球鞋→注重包裹性和防侧翻（中底支撑+高帮设计）；③休闲鞋→舒适度和颜值并重，无需专业性能；④尺码建议下午试穿（脚部会轻微肿胀），预留一指空隙；⑤不同品牌尺码可能有差异，建议参考具体尺码表。', 'product', '选购指南', '2026-04-18 01:40:46'),
(66, 'iPhone使用技巧-省电设置', 'iPhone省电技巧：①开启低电量模式（设置→电池→低电量模式）；②关闭后台App刷新（设置→通用→后台App刷新）；③降低屏幕亮度或开启自动亮度；④关闭定位服务（不使用的App）；⑤关闭动态效果（设置→辅助功能→动态效果→减弱）；⑥关闭5G（双卡管理中选择自动5G）。正常使用可延长20-30%续航。', 'product', '使用技巧', '2026-04-18 01:40:46'),
(67, '华为手机特色功能介绍', '华为手机独有功能：①卫星通话（Mate 60系列支持，无地面信号时紧急联络）；②鸿蒙多设备协同（平板/电脑/手机无缝流转）；③智感支付（识别扫码场景自动调出付款码）；④纯净模式（拦截骚扰电话和广告推送）；⑤中转站（跨应用拖拽文件）；⑥超级终端（附近设备一键连接）。', 'product', '使用技巧', '2026-04-18 01:40:46'),
(68, 'MacBook新手入门指南', 'MacBook初次使用建议：①熟悉触控板手势（三指拖移、四指切换桌面等）；②安装常用软件（App Store或官网下载）；③开启iCloud同步（照片、文件、备忘录跨设备）；④配置Touch ID指纹；⑤学习Spotlight搜索（Command+空格快速启动）；⑥了解Finder文件管理逻辑。推荐观看官方"Mac基础"视频教程。', 'product', '使用技巧', '2026-04-18 01:40:46'),
(69, '大家电安装注意事项', '冰箱安装：预留两侧各10cm以上散热空间，远离热源和阳光直射，保持水平放置（调节底脚）。洗衣机安装：需预留进水龙头和排水口（距离1米内），确认电源接地良好，首次使用需空洗一次清洁内筒。空调安装：室外机需固定在承重墙或专用支架上，高度高于室内机，管路长度不超过15米为宜。', 'logistics', '安装指南', '2026-04-18 01:40:46'),
(70, '退换货流程详解', '退货完整流程：①登录APP→我的订单→申请售后→选择"退货退款"；②选择退货原因（质量问题/不想要了/其他）并上传凭证照片；③等待客服审核（1-2个工作日）；④审核通过后系统返回寄回地址和运单号；⑤使用指定快递寄回（建议保留快递单号）；⑥仓库验收（1-3个工作日）→退款原路返回。换货流程类似，只是最后一步为重新发货而非退款。', 'policy', '售后政策', '2026-04-18 01:40:46'),
(71, '质量问题判定标准', '以下情况属于质量问题：①开箱即有外观损坏（划痕、裂纹、变形）；②功能异常（无法开机、屏幕坏点>3个、按键失灵等）；③性能不达标（续航明显低于标称值、充电异常发热等）；④配件缺失或错误。以下情况不属于质量问题：①正常使用产生的轻微磨损；②人为损坏（进水、摔落、挤压）；③拆机或私自维修后出现的问题；④超出保修期。', 'policy', '售后政策', '2026-04-18 01:40:46'),
(74, '物流时效承诺与赔偿', '物流时效承诺：一线城市订单承诺48小时内送达，超时每延迟24小时赔偿订单金额的1%（最高不超过50元）；二线城市72小时，三线城市96小时。不可抗力因素（自然灾害、疫情管控等）除外。如遇物流丢失或严重损坏，全额赔付并补偿50元优惠券。签收时请当场验货确认无误后再签字。', 'logistics', '物流政策', '2026-04-18 01:40:46'),
(75, '包装与开箱验货指南', '收到商品后请按以下步骤操作：①检查外包装是否完好无损（拍照留证）；②核对商品名称、数量、规格是否与订单一致；③开机测试基本功能（手机/电脑类）；④检查配件是否齐全（说明书、保修卡、充电器等）；⑤如发现问题立即联系客服并拒收（不要先签收再反馈）。大家电建议预约专业安装人员上门验收安装。', 'logistics', '配送服务', '2026-04-18 01:40:46'),
(79, '智能客服服务范围', '平台智能客服可处理以下问题：①订单状态查询与修改；②物流信息追踪；③退换货申请指导；④支付问题排查；⑤发票开具咨询；⑥产品参数查询；⑦促销活动说明。以下情况建议转人工客服：复杂售后纠纷、大额订单异常、投诉建议、特殊需求定制等。人工客服工作时间为9:00-22:00（工作日），10:00-18:00（周末）。', 'service', '客服政策', '2026-04-18 01:40:46'),
(80, '数据安全与隐私保护', '平台承诺严格保护用户隐私：①所有支付信息经过加密传输和存储（SSL/TLS协议）；②不向第三方出售或共享用户个人数据；③用户有权查看、修改、删除自己的个人信息（设置→隐私管理）；④客服对话内容加密保存，仅用于服务质量改进；⑤如遇账号异常或疑似泄露请立即联系客服冻结账户并修改密码。建议定期更换密码并开启两步验证。', 'policy', '安全政策', '2026-04-18 01:40:46'),
(83, '以旧换新服务说明', '平台支持手机、笔记本、平板等数码产品以旧换新：①在线估价（选择型号、成色、功能状态→系统给出预估价）；②确认后下单新机并提交旧机；③新机先发货（需支付差价）；④收到新机后7天内寄回旧机；⑤专业检测后最终定价（与预估价偏差±10%内正常）；⑥多退少补完成交易。旧机数据请提前备份并恢复出厂设置。', 'service', '增值服务', '2026-04-18 01:40:46'),
(91, '防诈骗安全提示', '警惕以下常见电商诈骗：①冒充客服退款（官方不会索要验证码或密码）；②虚假物流链接（请通过官方渠道查询）；③低价诱惑（远低于市场价多为假货或骗局）；④钓鱼网站（仔细核对域名是否正确）；⑤二维码付款（正规平台不会要求扫码转账）。如遇可疑情况立即挂断并通过官方渠道核实。已受骗用户请第一时间联系官方客服并报警（拨打110）。', 'policy', '安全政策', '2026-04-18 01:40:46');
